ent volume alone.","warning":true},{"label":"Key authority","value":"US Department of State — Embassy/Consulate in India"},{"label":"After approval","value":"Visa foil in passport; officer at port of entry decides admission length (often up to 6 months). No work permitted."}],"eligibility":[{"criterion":"Valid passport","met":true,"note":"6+ months validity recommended"},{"criterion":"Clear temporary purpose","met":true,"note":"Tourism, family, business meeting—not employment"},{"criterion":"Strong ties to India","met":true,"note":"Job, business, property, family"},{"criterion":"Proof of funds for trip","met":true,"note":"Bank statements, ITR, sponsor letter"},{"criterion":"DS-160 completed accurately","met":false,"note":"Must match interview answers"},{"criterion":"No prior visa fraud","met":true},{"criterion":"Interview appointment booked","met":false,"note":"Via ustraveldocs.com"}],"redFlagsBanner":"After 214(b) refusal, do not reapply immediately with unchanged profile. Strengthen ties evidence and visit purpose clarity first.","redFlags":[{"title":"Weak ties to India","description":"Unemployed, no assets, young single applicant with vague purpose.","fix":"Employment letter, business registration, property, family dependencies","severity":"Very common"},{"title":"214(b) — immigrant intent signals","description":"Mentions working in USA, long stay without reason, or visiting fiancé without clear plan.","fix":"Clear temporary purpose; return date; no employment intent","severity":"Very common"},{"title":"DS-160 inconsistencies","description":"Travel history, employment, or relatives in US not matching interview.","fix":"Review DS-160 line by line; practice consistent answers","severity":"Common"},{"title":"Prior refusals unchanged","description":"Reapplying without material change in circumstances.","fix":"Wait until ties strengthen; new purpose documentation","severity":"High"},{"title":"Insufficient funds","description":"Cannot explain who pays for trip or recen